import json, re, sys

patterns = [
    re.compile(r'(?i)\bDeere\b'),
    re.compile(r'(?i)\bJohn\s+Deere\b'),
    re.compile(r'\bDE\s'),
    re.compile(r'(?i)precision\s+agriculture'),
    re.compile(r'(?i)See\s*&\s*Spray'),
    re.compile(r'(?i)See\s+and\s+Spray'),
    re.compile(r'(?i)farm\s+automation'),
    re.compile(r'(?i)autonomous\s+tractor'),
    re.compile(r'(?i)right\s+to\s+repair'),
]

def check_text(text):
    if not text:
        return False
    for p in patterns:
        if p.search(text):
            return True
    return False

# --- CLAUDE DATA ---
print("=" * 80)
print("CLAUDE DATA - conversations.json")
print("=" * 80)

claude_path = "/tmp/deere_search/claude/conversations.json"
with open(claude_path, 'r', encoding='utf-8', errors='replace') as f:
    claude_data = json.load(f)

if isinstance(claude_data, list):
    print(f"Claude data is a list with {len(claude_data)} conversations")
    if len(claude_data) > 0:
        print(f"First item keys: {list(claude_data[0].keys()) if isinstance(claude_data[0], dict) else type(claude_data[0])}")
elif isinstance(claude_data, dict):
    print(f"Claude data is a dict with keys: {list(claude_data.keys())[:20]}")

matches_found = 0

def extract_conversation_text(conv):
    """Extract all text from a Claude conversation"""
    texts = []
    if isinstance(conv, dict):
        for key in ['name', 'title', 'summary']:
            if key in conv and conv[key]:
                texts.append(f"[{key}]: {conv[key]}")
        # Look for messages/chat_messages
        for msg_key in ['chat_messages', 'messages', 'content']:
            if msg_key in conv and isinstance(conv[msg_key], list):
                for msg in conv[msg_key]:
                    if isinstance(msg, dict):
                        sender = msg.get('sender', msg.get('role', 'unknown'))
                        # Get text content
                        text = msg.get('text', '')
                        if not text and 'content' in msg:
                            if isinstance(msg['content'], str):
                                text = msg['content']
                            elif isinstance(msg['content'], list):
                                for part in msg['content']:
                                    if isinstance(part, dict) and part.get('type') == 'text':
                                        text += part.get('text', '')
                                    elif isinstance(part, str):
                                        text += part
                        if text:
                            texts.append(f"[{sender}]: {text}")
    return '\n'.join(texts)

if isinstance(claude_data, list):
    for i, conv in enumerate(claude_data):
        full_text = extract_conversation_text(conv)
        if check_text(full_text):
            matches_found += 1
            print(f"\n{'='*60}")
            print(f"CLAUDE MATCH #{matches_found} - Conversation index {i}")
            conv_name = conv.get('name', conv.get('title', 'Untitled'))
            conv_uuid = conv.get('uuid', conv.get('id', 'unknown'))
            print(f"Name: {conv_name}")
            print(f"UUID: {conv_uuid}")
            print(f"Created: {conv.get('created_at', conv.get('created', 'unknown'))}")
            print(f"{'='*60}")
            # Print full conversation text
            print(full_text[:15000])
            if len(full_text) > 15000:
                print(f"\n... [truncated, total length: {len(full_text)} chars]")
elif isinstance(claude_data, dict):
    # Try searching recursively
    def search_recursive(obj, path=""):
        global matches_found
        if isinstance(obj, str) and check_text(obj):
            matches_found += 1
            print(f"\n--- CLAUDE MATCH #{matches_found} (path: {path}) ---")
            print(obj[:5000])
        elif isinstance(obj, dict):
            for k, v in obj.items():
                search_recursive(v, f"{path}.{k}")
        elif isinstance(obj, list):
            for i, v in enumerate(obj):
                search_recursive(v, f"{path}[{i}]")
    search_recursive(claude_data)

if matches_found == 0:
    print("No Deere-related content found in Claude data.")
print(f"\nTotal Claude matches: {matches_found}")

